// Generated by the TomTom Developer Docs portal.
// Drop this file into your project root as CLAUDE.md, or paste it as
// context into any AI coding assistant.

import { ROUTING_API_CLAUDE_CONTEXT } from './claude-context-routing-api';
import { MAP_DISPLAY_API_CLAUDE_CONTEXT } from './claude-context-map-display-api';
import { TRAFFIC_API_CLAUDE_CONTEXT } from './claude-context-traffic-api';
import { NAVSDK_ANDROID_CLAUDE_CONTEXT } from './claude-context-navsdk-android';
import { NAVSDK_IOS_CLAUDE_CONTEXT } from './claude-context-navsdk-ios';
import { UX_LIBRARY_CLAUDE_CONTEXT } from './claude-context-ux-library';

const HEADER = `# TomTom Developer Docs — Complete AI Context Bundle

> This file gives an AI coding assistant (Claude Code, Cursor, ChatGPT, Copilot, etc.)
> everything it needs to help you integrate TomTom APIs and SDKs.
> Drop it into your project root as \`CLAUDE.md\` or paste it as context.
>
> Generated by the TomTom Developer Docs portal — https://developer.tomtom.com
> Bundle date: ${new Date().toISOString().slice(0, 10)}

---

## What's in this bundle

| # | Product | Type | Status |
|---|---------|------|--------|
| 1 | Routing API | REST API | Production (v1), Public Preview (v2), Private Preview (v3) |
| 2 | Map Display API | REST API | Production (v1), Public Preview (v2), Private Preview (v3) |
| 3 | Traffic API | REST API | Production |
| 4 | Maps & Navigation SDK — Android | Native SDK | Production |
| 5 | Maps & Navigation SDK — iOS | Native SDK | Production |
| 6 | Android UX Library | UI Component Library | Production |

---

> **Tip for AI assistants:** Read the table of contents above to understand which sections
> apply to your current task. You do not need to load everything into working memory at once.

`;

const SEPARATOR = (n, title) => `

---
---

# Part ${n}: ${title}

---

`;

export const FULL_BUNDLE_CONTEXT =
  HEADER +
  SEPARATOR(1, 'Routing API') + ROUTING_API_CLAUDE_CONTEXT +
  SEPARATOR(2, 'Map Display API') + MAP_DISPLAY_API_CLAUDE_CONTEXT +
  SEPARATOR(3, 'Traffic API') + TRAFFIC_API_CLAUDE_CONTEXT +
  SEPARATOR(4, 'Maps & Navigation SDK — Android') + NAVSDK_ANDROID_CLAUDE_CONTEXT +
  SEPARATOR(5, 'Maps & Navigation SDK — iOS') + NAVSDK_IOS_CLAUDE_CONTEXT +
  SEPARATOR(6, 'Android UX Library') + UX_LIBRARY_CLAUDE_CONTEXT;

export function downloadFullBundle() {
  const blob = new Blob([FULL_BUNDLE_CONTEXT], { type: 'text/markdown;charset=utf-8' });
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url;
  a.download = 'tomtom-ai-context-bundle.md';
  document.body.appendChild(a);
  a.click();
  document.body.removeChild(a);
  URL.revokeObjectURL(url);
}
